66	
67	export const useDawStore = create<DawStore>()((set, get) => ({
68	  // Transport defaults
69	  transportState: "stopped",
70	  bpm: 120,
71	  cursorSeconds: 0,
72	  loopEnabled: false,
73	  loopStart: 0,
74	  loopEnd: 0,
75	
76	  // Engine defaults
77	  engineStatus: "uninitialized",
78	
79	  // Track & clip defaults
80	  tracks: [],
81	  clips: {},
82	  selectedTrackIds: [],
83	  selectedClipIds: [],
84	
85	  // Transport actions
86	  play: () => {
87	    set({ transportState: "playing" });
88	  },
89	  pause: () => {
90	    set({ transportState: "paused" });
91	  },
92	  stop: () => {
93	    set({ transportState: "stopped", cursorSeconds: 0 });
94	  },
95	  setBpm: (bpm: number) => {
96	    const clamped = Math.min(999, Math.max(20, bpm));
97	    if (!Number.isFinite(clamped)) return;
98	    set({ bpm: clamped });
99	  },
100	  setCursor: (seconds: number) => {
101	    set({ cursorSeconds: seconds });
102	  },
103	  setLoop: (enabled: boolean, start?: number, end?: number) => {
104	    set((state) => ({
105	      loopEnabled: enabled,
106	      loopStart: start ?? state.loopStart,
107	      loopEnd: end ?? state.loopEnd,
108	    }));
109	  },
110	
111	  // Engine actions
112	  setEngineStatus: (status: AudioEngineStatus) => {
113	    set({ engineStatus: status });
114	  },
115	
116	  // Track actions
117	  addTrack: (track: TrackModel, index?: number) => {
118	    set((state) => {
119	      const next = [...state.tracks];
120	      if (index !== undefined) {
121	        next.splice(index, 0, track);
122	      } else {
123	        next.push(track);
124	      }
125	      return { tracks: next };
126	    });
127	  },
128	
129	  removeTrack: (id: string) => {
130	    set((state) => {
131	      const track = state.tracks.find((t) => t.id === id);
132	      if (!track) return state;
133	      const removeSet = new Set(track.clipIds);
134	      const nextClips = Object.fromEntries(
135	        Object.entries(state.clips).filter(([k]) => !removeSet.has(k)),
136	      );
137	      return {
138	        tracks: state.tracks.filter((t) => t.id !== id),
139	        clips: nextClips,
140	      };
141	    });
142	  },
143	
144	  updateTrack: (id: string, patch: Partial<Omit<TrackModel, "id">>) => {
145	    set((state) => ({
146	      tracks: state.tracks.map((t) => (t.id === id ? { ...t, ...patch } : t)),
147	    }));
148	  },
149	
150	  reorderTrack: (id: string, toIndex: number) => {
151	    set((state) => {
152	      const fromIndex = state.tracks.findIndex((t) => t.id === id);
153	      if (fromIndex === -1) return state;
154	      const next = [...state.tracks];
155	      const moved = next.splice(fromIndex, 1)[0];
156	      if (moved === undefined) return state;
157	      next.splice(toIndex, 0, moved);
158	      return { tracks: next };
159	    });
160	  },
161	
162	  // Clip actions
163	  addClip: (clip: ClipModel) => {
164	    set((state) => {
165	      const nextClips = { ...state.clips, [clip.id]: clip };
166	      const tracks = state.tracks.map((t) =>
167	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, clip.id] } : t,
168	      );
169	      return { clips: nextClips, tracks };
170	    });
171	  },
172	
173	  removeClip: (id: string) => {
174	    set((state) => {
175	      const clip = state.clips[id];
176	      if (!clip) return state;
177	      const nextClips = Object.fromEntries(
178	        Object.entries(state.clips).filter(([k]) => k !== id),
179	      );
180	      const tracks = state.tracks.map((t) =>
181	        t.id === clip.trackId
182	          ? { ...t, clipIds: t.clipIds.filter((cid) => cid !== id) }
183	          : t,
184	      );
185	      return { clips: nextClips, tracks };
186	    });
187	  },
188	
189	  moveClip: (id: string, startTime: number, toTrackId?: string) => {
190	    set((state) => {
191	      const clip = state.clips[id];
192	      if (!clip) return state;
193	      const updatedClip = {
194	        ...clip,
195	        startTime,
196	        trackId: toTrackId ?? clip.trackId,
197	      };
198	      const nextClips = { ...state.clips, [id]: updatedClip };
199	
200	      let tracks = state.tracks;
201	      if (toTrackId !== undefined && toTrackId !== clip.trackId) {
202	        tracks = tracks.map((t) => {
203	          if (t.id === clip.trackId) {
204	            return { ...t, clipIds: t.clipIds.filter((cid) => cid !== id) };
205	          }
206	          if (t.id === toTrackId) {
207	            return { ...t, clipIds: [...t.clipIds, id] };
208	          }
209	          return t;
210	        });
211	      }
212	      return { clips: nextClips, tracks };
213	    });
214	  },
215	
216	  splitClip: (id: string, atTime: number, providedId?: string): string | undefined => {
217	    const state = get();
218	    const clip = state.clips[id];
219	    if (!clip) return undefined;
220	
221	    const clipEnd = clip.startTime + clip.duration;
222	    if (atTime <= clip.startTime || atTime >= clipEnd) return undefined;
223	
224	    const leftDuration = atTime - clip.startTime;
225	    const rightDuration = clip.duration - leftDuration;
226	    const rightSourceOffset = clip.sourceOffset + leftDuration;
227	
228	    const newId = providedId ?? nextClipId();
229	
230	    const leftClip: ClipModel = { ...clip, duration: leftDuration };
231	    const rightClip: ClipModel = {
232	      ...clip,
233	      id: newId,
234	      startTime: atTime,
235	      sourceOffset: rightSourceOffset,
236	      duration: rightDuration,
237	    };
238	
239	    set((s) => {
240	      const nextClips = { ...s.clips, [id]: leftClip, [newId]: rightClip };
241	      const tracks = s.tracks.map((t) =>
242	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, newId] } : t,
243	      );
244	      return { clips: nextClips, tracks };
245	    });
246	
247	    return newId;
248	  },
249	
250	  trimClip: (id: string, newStart?: number, newEnd?: number) => {
251	    set((state) => {
252	      const clip = state.clips[id];
253	      if (!clip) return state;
254	
255	      let { startTime, sourceOffset, duration } = clip;
256	      const clipEnd = startTime + duration;
257	
258	      if (newStart !== undefined) {
259	        const delta = newStart - startTime;
260	        startTime = newStart;
261	        sourceOffset = sourceOffset + delta;
262	        duration = clipEnd - newStart;
263	      }
264	
265	      if (newEnd !== undefined) {
266	        duration = newEnd - startTime;
267	      }
268	
269	      // Guard against invalid state
270	      if (duration <= 0 || sourceOffset < 0) return state;
271	
272	      return {
273	        clips: {
274	          ...state.clips,
275	          [id]: { ...clip, startTime, sourceOffset, duration },
276	        },
277	      };
278	    });
279	  },
280	
281	  duplicateClip: (id: string, providedId?: string): string | undefined => {
282	    const state = get();
283	    const clip = state.clips[id];
284	    if (!clip) return undefined;
285	
286	    const newId = providedId ?? nextClipId();
287	    const duplicate: ClipModel = {
288	      ...clip,
289	      id: newId,
290	      startTime: clip.startTime + clip.duration,
291	    };
292	
293	    set((s) => {
294	      const nextClips = { ...s.clips, [newId]: duplicate };
295	      const tracks = s.tracks.map((t) =>
296	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, newId] } : t,
297	      );
298	      return { clips: nextClips, tracks };
299	    });
300	
301	    return newId;
302	  },
303	
304	  // Selection
305	  setSelectedTrackIds: (ids: readonly string[]) => {
306	    set({ selectedTrackIds: ids });
307	  },
308	  setSelectedClipIds: (ids: readonly string[]) => {
309	    set({ selectedClipIds: ids });
310	  },
311	
312	  // Query
313	  queryClipsAtTime: (time: number): readonly ClipModel[] => {
314	    const state = get();
315	    const hasSolo = state.tracks.some((t) => t.solo);
316	    const activeTracks = new Set(
317	      state.tracks
318	        .filter((t) => {
319	          if (t.muted) return false;
320	          if (hasSolo && !t.solo) return false;
321	          return true;
322	        })
323	        .map((t) => t.id),
324	    );
325	
326	    return Object.values(state.clips).filter((clip) => {
327	      if (!activeTracks.has(clip.trackId)) return false;
328	      const clipEnd = clip.startTime + clip.duration;
329	      return time >= clip.startTime && time < clipEnd;
330	    });
331	  },
332	}));
