1	import type { UndoCommand } from "@state/undo/undo-command";
2	import { useDawStore } from "@state/store";
3	import type { TrackModel, ClipModel } from "@state/track/types";
4	
5	function getStore(): ReturnType<typeof useDawStore.getState> {
6	  return useDawStore.getState();
7	}
8	
9	// ---------------------------------------------------------------------------
10	// AddTrackCommand / RemoveTrackCommand
11	// ---------------------------------------------------------------------------
12	
13	export class AddTrackCommand implements UndoCommand {
14	  readonly type = "add-track";
15	
16	  constructor(
17	    private readonly track: TrackModel,
18	    private readonly index?: number,
19	  ) {}
20	
21	  execute(): void {
22	    getStore().addTrack(this.track, this.index);
23	  }
24	
25	  undo(): void {
26	    getStore().removeTrack(this.track.id);
27	  }
28	
29	  serialize(): Record<string, unknown> {
30	    return { track: this.track, index: this.index };
31	  }
32	}
33	
34	export class RemoveTrackCommand implements UndoCommand {
35	  readonly type = "remove-track";
36	
37	  private savedTrack: TrackModel | undefined;
38	  private savedClips: readonly ClipModel[] = [];
39	  private savedIndex = -1;
40	
41	  constructor(private readonly trackId: string) {}
42	
43	  execute(): void {
44	    const state = getStore();
45	    this.savedIndex = state.tracks.findIndex((t) => t.id === this.trackId);
46	    this.savedTrack = state.tracks.find((t) => t.id === this.trackId);
47	
48	    if (this.savedTrack) {
49	      this.savedClips = this.savedTrack.clipIds
50	        .map((cid) => state.clips[cid])
51	        .filter((c): c is ClipModel => c !== undefined);
52	    }
53	
54	    state.removeTrack(this.trackId);
55	  }
56	
57	  undo(): void {
58	    if (this.savedTrack === undefined) return;
59	
60	    // Re-add the track at its original position (without clips first)
61	    const trackWithoutClips: TrackModel = { ...this.savedTrack, clipIds: [] };
62	    getStore().addTrack(trackWithoutClips, this.savedIndex);
63	
64	    // Re-add all clips (addClip also wires up clipIds)
65	    for (const clip of this.savedClips) {
66	      getStore().addClip(clip);
67	    }
68	  }
69	
70	  serialize(): Record<string, unknown> {
71	    return { trackId: this.trackId };
72	  }
73	}
74	
75	// ---------------------------------------------------------------------------
76	// UpdateTrackCommand
77	// ---------------------------------------------------------------------------
78	
79	export class UpdateTrackCommand implements UndoCommand {
80	  readonly type = "update-track";
81	
82	  private oldPatch: Partial<Omit<TrackModel, "id">> | undefined;
83	
84	  constructor(
85	    private readonly trackId: string,
86	    private readonly newPatch: Partial<Omit<TrackModel, "id">>,
87	  ) {}
88	
89	  execute(): void {
90	    const track = getStore().tracks.find((t) => t.id === this.trackId);
91	    if (track === undefined) return;
92	
93	    // Capture old values for only the keys being changed
94	    const old: Record<string, unknown> = {};
95	    for (const key of Object.keys(this.newPatch)) {
96	      old[key] = track[key as keyof TrackModel];
97	    }
98	    this.oldPatch = old as Partial<Omit<TrackModel, "id">>;
99	
100	    getStore().updateTrack(this.trackId, this.newPatch);
101	  }
102	
103	  undo(): void {
104	    if (this.oldPatch === undefined) return;
105	    getStore().updateTrack(this.trackId, this.oldPatch);
106	  }
107	
108	  serialize(): Record<string, unknown> {
109	    return {
110	      trackId: this.trackId,
111	      newPatch: this.newPatch,
112	      oldPatch: this.oldPatch,
113	    };
114	  }
115	}
116	
117	// ---------------------------------------------------------------------------
118	// ReorderTrackCommand
119	// ---------------------------------------------------------------------------
120	
121	export class ReorderTrackCommand implements UndoCommand {
122	  readonly type = "reorder-track";
123	
124	  private fromIndex = -1;
125	
126	  constructor(
127	    private readonly trackId: string,
128	    private readonly toIndex: number,
129	  ) {}
130	
131	  execute(): void {
132	    this.fromIndex = getStore().tracks.findIndex((t) => t.id === this.trackId);
133	    getStore().reorderTrack(this.trackId, this.toIndex);
134	  }
135	
136	  undo(): void {
137	    if (this.fromIndex === -1) return;
138	    getStore().reorderTrack(this.trackId, this.fromIndex);
139	  }
140	
141	  serialize(): Record<string, unknown> {
142	    return {
143	      trackId: this.trackId,
144	      fromIndex: this.fromIndex,
145	      toIndex: this.toIndex,
146	    };
147	  }
148	}
149	
150	// ---------------------------------------------------------------------------
151	// AddClipCommand / RemoveClipCommand
152	// ---------------------------------------------------------------------------
153	
154	export class AddClipCommand implements UndoCommand {
155	  readonly type = "add-clip";
156	
157	  constructor(private readonly clip: ClipModel) {}
158	
159	  execute(): void {
160	    getStore().addClip(this.clip);
161	  }
162	
163	  undo(): void {
164	    getStore().removeClip(this.clip.id);
165	  }
166	
167	  serialize(): Record<string, unknown> {
168	    return { clip: this.clip };
169	  }
170	}
171	
172	export class RemoveClipCommand implements UndoCommand {
173	  readonly type = "remove-clip";
174	
175	  private savedClip: ClipModel | undefined;
176	
177	  constructor(private readonly clipId: string) {}
178	
179	  execute(): void {
180	    this.savedClip = getStore().clips[this.clipId];
181	    getStore().removeClip(this.clipId);
182	  }
183	
184	  undo(): void {
185	    if (this.savedClip === undefined) return;
186	    getStore().addClip(this.savedClip);
187	  }
188	
189	  serialize(): Record<string, unknown> {
190	    return { clipId: this.clipId };
191	  }
192	}
193	
194	// ---------------------------------------------------------------------------
195	// MoveClipCommand
196	// ---------------------------------------------------------------------------
197	
198	export class MoveClipCommand implements UndoCommand {
199	  readonly type = "move-clip";
200	
201	  private oldStartTime = 0;
202	  private oldTrackId = "";
203	
204	  constructor(
205	    private readonly clipId: string,
206	    private readonly newStartTime: number,
207	    private readonly newTrackId?: string,
208	  ) {}
209	
210	  execute(): void {
211	    const clip = getStore().clips[this.clipId];
212	    if (clip === undefined) return;
213	
214	    this.oldStartTime = clip.startTime;
215	    this.oldTrackId = clip.trackId;
216	
217	    getStore().moveClip(this.clipId, this.newStartTime, this.newTrackId);
218	  }
219	
220	  undo(): void {
221	    getStore().moveClip(this.clipId, this.oldStartTime, this.oldTrackId);
222	  }
223	
224	  serialize(): Record<string, unknown> {
225	    return {
226	      clipId: this.clipId,
227	      newStartTime: this.newStartTime,
228	      newTrackId: this.newTrackId,
229	      oldStartTime: this.oldStartTime,
230	      oldTrackId: this.oldTrackId,
231	    };
232	  }
233	}
