235	// ---------------------------------------------------------------------------
236	// SplitClipCommand
237	// ---------------------------------------------------------------------------
238	
239	export class SplitClipCommand implements UndoCommand {
240	  readonly type = "split-clip";
241	
242	  private originalClip: ClipModel | undefined;
243	  private generatedRightId: string | undefined;
244	
245	  constructor(
246	    private readonly clipId: string,
247	    private readonly atTime: number,
248	  ) {}
249	
250	  rightClipId(): string | undefined {
251	    return this.generatedRightId;
252	  }
253	
254	  execute(): void {
255	    // Capture full original clip before split
256	    this.originalClip = getStore().clips[this.clipId];
257	    // Pass stored ID on redo to keep clip references deterministic
258	    this.generatedRightId = getStore().splitClip(this.clipId, this.atTime, this.generatedRightId);
259	  }
260	
261	  undo(): void {
262	    if (this.originalClip === undefined) return;
263	
264	    // Remove the right clip created by split
265	    if (this.generatedRightId !== undefined) {
266	      getStore().removeClip(this.generatedRightId);
267	    }
268	
269	    // Restore original clip state (splitClip mutated the left clip in-place)
270	    useDawStore.setState((state) => ({
271	      clips: { ...state.clips, [this.clipId]: this.originalClip as ClipModel },
272	    }));
273	  }
274	
275	  serialize(): Record<string, unknown> {
276	    return {
277	      clipId: this.clipId,
278	      atTime: this.atTime,
279	      rightClipId: this.generatedRightId,
280	      originalClip: this.originalClip,
281	    };
282	  }
283	}
284	
285	// ---------------------------------------------------------------------------
286	// TrimClipCommand
287	// ---------------------------------------------------------------------------
288	
289	export class TrimClipCommand implements UndoCommand {
290	  readonly type = "trim-clip";
291	
292	  private savedClip: ClipModel | undefined;
293	
294	  constructor(
295	    private readonly clipId: string,
296	    private readonly newStart: number | undefined,
297	    private readonly newEnd: number | undefined,
298	  ) {}
299	
300	  execute(): void {
301	    this.savedClip = getStore().clips[this.clipId];
302	    getStore().trimClip(this.clipId, this.newStart, this.newEnd);
303	  }
304	
305	  undo(): void {
306	    if (this.savedClip === undefined) return;
307	    useDawStore.setState((state) => ({
308	      clips: { ...state.clips, [this.clipId]: this.savedClip as ClipModel },
309	    }));
310	  }
311	
312	  serialize(): Record<string, unknown> {
313	    return {
314	      clipId: this.clipId,
315	      newStart: this.newStart,
316	      newEnd: this.newEnd,
317	    };
318	  }
319	}
320	
321	// ---------------------------------------------------------------------------
322	// DuplicateClipCommand
323	// ---------------------------------------------------------------------------
324	
325	export class DuplicateClipCommand implements UndoCommand {
326	  readonly type = "duplicate-clip";
327	
328	  private generatedId: string | undefined;
329	
330	  constructor(private readonly clipId: string) {}
331	
332	  duplicatedClipId(): string | undefined {
333	    return this.generatedId;
334	  }
335	
336	  execute(): void {
337	    // Pass stored ID on redo to keep clip references deterministic
338	    this.generatedId = getStore().duplicateClip(this.clipId, this.generatedId);
339	  }
340	
341	  undo(): void {
342	    if (this.generatedId === undefined) return;
343	    getStore().removeClip(this.generatedId);
344	  }
345	
346	  serialize(): Record<string, unknown> {
347	    return { clipId: this.clipId, duplicatedId: this.generatedId };
348	  }
349	}
