222	    if (atTime <= clip.startTime || atTime >= clipEnd) return undefined;
223	
224	    const leftDuration = atTime - clip.startTime;
225	    const rightDuration = clip.duration - leftDuration;
226	    const rightSourceOffset = clip.sourceOffset + leftDuration;
227	
228	    const newId = providedId ?? nextClipId();
229	
230	    const leftClip: ClipModel = { ...clip, duration: leftDuration };
231	    const rightClip: ClipModel = {
232	      ...clip,
233	      id: newId,
234	      startTime: atTime,
235	      sourceOffset: rightSourceOffset,
236	      duration: rightDuration,
237	    };
238	
239	    set((s) => {
240	      const nextClips = { ...s.clips, [id]: leftClip, [newId]: rightClip };
241	      const tracks = s.tracks.map((t) =>
242	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, newId] } : t,
243	      );
244	      return { clips: nextClips, tracks };
245	    });
246	
247	    return newId;
248	  },
