251	    set((state) => {
252	      const clip = state.clips[id];
253	      if (!clip) return state;
254	
255	      let { startTime, sourceOffset, duration } = clip;
256	      const clipEnd = startTime + duration;
257	
258	      if (newStart !== undefined) {
259	        const delta = newStart - startTime;
260	        startTime = newStart;
261	        sourceOffset = sourceOffset + delta;
262	        duration = clipEnd - newStart;
263	      }
264	
265	      if (newEnd !== undefined) {
266	        duration = newEnd - startTime;
267	      }
268	
269	      // Guard against invalid state
270	      if (duration <= 0 || sourceOffset < 0) return state;
271	
272	      return {
273	        clips: {
274	          ...state.clips,
275	          [id]: { ...clip, startTime, sourceOffset, duration },
276	        },
277	      };
278	    });
279	  },
