import { describe, it, expect, beforeEach } from "vitest";
import { useDawStore } from "@state/store";
import { sessionSchema, createDefaultSession } from "./session-schema";
import { hydrateStore } from "./use-session-persistence";
import type { TrackModel, ClipModel } from "@state/track/index";
import type { SessionSchema } from "./session-schema";

/** Helper: build a minimal track */
function makeTrack(overrides: Partial<TrackModel> = {}): TrackModel {
  return {
    id: "track-1",
    name: "Audio 1",
    type: "audio",
    color: "#ff0000",
    muted: false,
    solo: false,
    armed: false,
    volume: 1,
    pan: 0,
    clipIds: [],
    ...overrides,
  };
}

/** Helper: build a minimal clip */
function makeClip(overrides: Partial<ClipModel> = {}): ClipModel {
  return {
    id: "clip-1",
    trackId: "track-1",
    sourceId: "source-1",
    startTime: 0,
    sourceOffset: 0,
    duration: 4,
    gain: 1,
    fadeIn: 0,
    fadeOut: 0,
    name: "Clip 1",
    ...overrides,
  };
}

/**
 * Simulate storeToSession by reading from the store.
 * We import the real function indirectly by calling the internal helper.
 * Since storeToSession is not exported, we build the session the same way
 * and validate via schema.
 */
function storeToSessionForTest(): SessionSchema {
  const state = useDawStore.getState();
  const clipsArray = Object.values(state.clips);
  return {
    version: 1,
    meta: { name: "Test", createdAt: 0, updatedAt: 0 },
    transport: {
      bpm: state.bpm,
      loopEnabled: state.loopEnabled,
      loopStart: state.loopStart,
      loopEnd: state.loopEnd,
    },
    tracks: state.tracks.map((t) => ({ ...t })),
    clips: clipsArray,
    mixer: { masterVolume: 1 },
  };
}

describe("Session tracks round-trip", () => {
  beforeEach(() => {
    useDawStore.setState({
      transportState: "stopped",
      bpm: 120,
      cursorSeconds: 0,
      loopEnabled: false,
      loopStart: 0,
      loopEnd: 0,
      engineStatus: "uninitialized",
      tracks: [],
      clips: {},
      selectedTrackIds: [],
      selectedClipIds: [],
    });
  });

  it("round-trips an empty session (no tracks/clips)", () => {
    const session = storeToSessionForTest();
    const parsed = sessionSchema.parse(session);

    expect(parsed.tracks).toEqual([]);
    expect(parsed.clips).toEqual([]);

    hydrateStore(parsed);
    const state = useDawStore.getState();
    expect(state.tracks).toEqual([]);
    expect(state.clips).toEqual({});
  });

  it("round-trips a single track with no clips", () => {
    const track = makeTrack();
    useDawStore.setState({ tracks: [track] });

    const session = storeToSessionForTest();
    const parsed = sessionSchema.parse(session);

    expect(parsed.tracks).toHaveLength(1);
    expect(parsed.tracks[0].id).toBe("track-1");
    expect(parsed.tracks[0].name).toBe("Audio 1");

    // Reset and hydrate
    useDawStore.setState({ tracks: [], clips: {} });
    hydrateStore(parsed);

    const state = useDawStore.getState();
    expect(state.tracks).toHaveLength(1);
    expect(state.tracks[0].id).toBe("track-1");
  });

  it("round-trips tracks with clips", () => {
    const clip1 = makeClip({ id: "clip-1", trackId: "track-1" });
    const clip2 = makeClip({
      id: "clip-2",
      trackId: "track-1",
      startTime: 4,
      name: "Clip 2",
    });
    const track = makeTrack({ clipIds: ["clip-1", "clip-2"] });

    useDawStore.setState({
      tracks: [track],
      clips: { "clip-1": clip1, "clip-2": clip2 },
    });

    const session = storeToSessionForTest();
    const parsed = sessionSchema.parse(session);

    expect(parsed.tracks).toHaveLength(1);
    expect(parsed.clips).toHaveLength(2);

    // Reset and hydrate
    useDawStore.setState({ tracks: [], clips: {} });
    hydrateStore(parsed);

    const state = useDawStore.getState();
    expect(state.tracks).toHaveLength(1);
    expect(state.tracks[0].clipIds).toEqual(["clip-1", "clip-2"]);
    expect(Object.keys(state.clips)).toHaveLength(2);
    expect(state.clips["clip-1"].name).toBe("Clip 1");
    expect(state.clips["clip-2"].startTime).toBe(4);
  });

  it("round-trips multiple tracks", () => {
    const t1 = makeTrack({ id: "t1", name: "Guitar", type: "audio" });
    const t2 = makeTrack({
      id: "t2",
      name: "Synth",
      type: "instrument",
      color: "#00ff00",
    });

    useDawStore.setState({ tracks: [t1, t2] });

    const session = storeToSessionForTest();
    const parsed = sessionSchema.parse(session);

    expect(parsed.tracks).toHaveLength(2);

    useDawStore.setState({ tracks: [], clips: {} });
    hydrateStore(parsed);

    const state = useDawStore.getState();
    expect(state.tracks).toHaveLength(2);
    expect(state.tracks[0].name).toBe("Guitar");
    expect(state.tracks[1].type).toBe("instrument");
  });

  it("preserves track properties through round-trip", () => {
    const track = makeTrack({
      muted: true,
      solo: true,
      armed: true,
      volume: 0.5,
      pan: -0.75,
    });
    useDawStore.setState({ tracks: [track] });

    const session = storeToSessionForTest();
    const parsed = sessionSchema.parse(session);

    useDawStore.setState({ tracks: [], clips: {} });
    hydrateStore(parsed);

    const restored = useDawStore.getState().tracks[0];
    expect(restored.muted).toBe(true);
    expect(restored.solo).toBe(true);
    expect(restored.armed).toBe(true);
    expect(restored.volume).toBe(0.5);
    expect(restored.pan).toBe(-0.75);
  });

  it("preserves clip properties through round-trip", () => {
    const clip = makeClip({
      sourceOffset: 2.5,
      gain: 0.8,
      fadeIn: 0.1,
      fadeOut: 0.3,
    });
    const track = makeTrack({ clipIds: ["clip-1"] });

    useDawStore.setState({ tracks: [track], clips: { "clip-1": clip } });

    const session = storeToSessionForTest();
    const parsed = sessionSchema.parse(session);

    useDawStore.setState({ tracks: [], clips: {} });
    hydrateStore(parsed);

    const restored = useDawStore.getState().clips["clip-1"];
    expect(restored.sourceOffset).toBe(2.5);
    expect(restored.gain).toBe(0.8);
    expect(restored.fadeIn).toBe(0.1);
    expect(restored.fadeOut).toBe(0.3);
  });

  it("schema rejects invalid track data", () => {
    const session = createDefaultSession();
    const bad = {
      ...session,
      tracks: [{ id: 123 }], // id should be string
      clips: [],
    };
    const result = sessionSchema.safeParse(bad);
    expect(result.success).toBe(false);
  });

  it("schema rejects invalid clip data", () => {
    const session = createDefaultSession();
    const bad = {
      ...session,
      clips: [{ id: "c1", startTime: -5 }], // startTime min 0, missing fields
    };
    const result = sessionSchema.safeParse(bad);
    expect(result.success).toBe(false);
  });

  it("converts clips Record to array and back", () => {
    const clip = makeClip();
    const track = makeTrack({ clipIds: ["clip-1"] });

    useDawStore.setState({ tracks: [track], clips: { "clip-1": clip } });

    const session = storeToSessionForTest();
    // clips in session should be an array
    expect(Array.isArray(session.clips)).toBe(true);

    const parsed = sessionSchema.parse(session);
    hydrateStore(parsed);

    // clips in store should be a Record
    const state = useDawStore.getState();
    expect(typeof state.clips).toBe("object");
    expect(Array.isArray(state.clips)).toBe(false);
    expect(state.clips["clip-1"].id).toBe("clip-1");
  });
});

import { describe, it, expect, beforeEach } from "vitest";
import { useDawStore } from "@state/store";
import type { ClipModel, TrackModel } from "./types";

function makeTrack(overrides: Partial<TrackModel> = {}): TrackModel {
  return {
    id: "track-1",
    name: "Track 1",
    type: "audio",
    color: "#ff2d6f",
    muted: false,
    solo: false,
    armed: false,
    volume: 1,
    pan: 0,
    clipIds: [],
    ...overrides,
  };
}

function makeClip(overrides: Partial<ClipModel> = {}): ClipModel {
  return {
    id: "clip-1",
    trackId: "track-1",
    sourceId: "source-1",
    startTime: 0,
    sourceOffset: 0,
    duration: 4,
    gain: 1,
    fadeIn: 0,
    fadeOut: 0,
    name: "Clip 1",
    ...overrides,
  };
}

/** Safe track access that fails the test if track is missing. */
function getTrack(index: number): TrackModel {
  const track = useDawStore.getState().tracks[index];
  expect(track).toBeDefined();
  return track as TrackModel;
}

/** Safe clip access that fails the test if clip is missing. */
function getClip(id: string): ClipModel {
  const clip = useDawStore.getState().clips[id];
  expect(clip).toBeDefined();
  return clip as ClipModel;
}

describe("Track store", () => {
  beforeEach(() => {
    useDawStore.setState({
      tracks: [],
      clips: {},
      selectedTrackIds: [],
      selectedClipIds: [],
    });
  });

  describe("addTrack", () => {
    it("adds a track to the store", () => {
      const track = makeTrack();
      useDawStore.getState().addTrack(track);
      expect(useDawStore.getState().tracks).toHaveLength(1);
      expect(useDawStore.getState().tracks[0]).toEqual(track);
    });

    it("adds multiple tracks in order", () => {
      useDawStore.getState().addTrack(makeTrack({ id: "t1", name: "T1" }));
      useDawStore.getState().addTrack(makeTrack({ id: "t2", name: "T2" }));
      const { tracks } = useDawStore.getState();
      expect(tracks).toHaveLength(2);
      expect(getTrack(0).id).toBe("t1");
      expect(getTrack(1).id).toBe("t2");
    });

    it("adds track at specific index", () => {
      useDawStore.getState().addTrack(makeTrack({ id: "t1" }));
      useDawStore.getState().addTrack(makeTrack({ id: "t3" }));
      useDawStore.getState().addTrack(makeTrack({ id: "t2" }), 1);
      const ids = useDawStore.getState().tracks.map((t) => t.id);
      expect(ids).toEqual(["t1", "t2", "t3"]);
    });
  });

  describe("removeTrack", () => {
    it("removes a track and its clips", () => {
      useDawStore.getState().addTrack(makeTrack({ id: "t1" }));
      useDawStore.getState().addClip(makeClip({ id: "c1", trackId: "t1" }));
      useDawStore.getState().removeTrack("t1");
      expect(useDawStore.getState().tracks).toHaveLength(0);
      expect(useDawStore.getState().clips["c1"]).toBeUndefined();
    });

    it("no-ops for unknown track id", () => {
      useDawStore.getState().addTrack(makeTrack({ id: "t1" }));
      useDawStore.getState().removeTrack("unknown");
      expect(useDawStore.getState().tracks).toHaveLength(1);
    });
  });

  describe("updateTrack", () => {
    it("updates track fields", () => {
      useDawStore.getState().addTrack(makeTrack({ id: "t1" }));
      useDawStore
        .getState()
        .updateTrack("t1", { name: "Renamed", muted: true });
      const track = getTrack(0);
      expect(track.name).toBe("Renamed");
      expect(track.muted).toBe(true);
    });
  });

  describe("reorderTrack", () => {
    it("moves a track to a new position", () => {
      useDawStore.getState().addTrack(makeTrack({ id: "t1" }));
      useDawStore.getState().addTrack(makeTrack({ id: "t2" }));
      useDawStore.getState().addTrack(makeTrack({ id: "t3" }));
      useDawStore.getState().reorderTrack("t3", 0);
      const ids = useDawStore.getState().tracks.map((t) => t.id);
      expect(ids).toEqual(["t3", "t1", "t2"]);
    });
  });

  describe("addClip", () => {
    it("adds a clip to the clips map and track clipIds", () => {
      useDawStore.getState().addTrack(makeTrack({ id: "t1" }));
      useDawStore.getState().addClip(makeClip({ id: "c1", trackId: "t1" }));
      expect(useDawStore.getState().clips["c1"]).toBeDefined();
      expect(getTrack(0).clipIds).toContain("c1");
    });
  });

  describe("removeClip", () => {
    it("removes a clip from map and track clipIds", () => {
      useDawStore.getState().addTrack(makeTrack({ id: "t1" }));
      useDawStore.getState().addClip(makeClip({ id: "c1", trackId: "t1" }));
      useDawStore.getState().removeClip("c1");
      expect(useDawStore.getState().clips["c1"]).toBeUndefined();
      expect(getTrack(0).clipIds).not.toContain("c1");
    });
  });

  describe("moveClip", () => {
    it("changes clip startTime", () => {
      useDawStore.getState().addTrack(makeTrack({ id: "t1" }));
      useDawStore
        .getState()
        .addClip(makeClip({ id: "c1", trackId: "t1", startTime: 0 }));
      useDawStore.getState().moveClip("c1", 5.0);
      expect(getClip("c1").startTime).toBe(5.0);
    });

    it("moves clip to a different track", () => {
      useDawStore.getState().addTrack(makeTrack({ id: "t1" }));
      useDawStore.getState().addTrack(makeTrack({ id: "t2" }));
      useDawStore
        .getState()
        .addClip(makeClip({ id: "c1", trackId: "t1", startTime: 0 }));
      useDawStore.getState().moveClip("c1", 2.0, "t2");
      const clip = getClip("c1");
      expect(clip.trackId).toBe("t2");
      expect(clip.startTime).toBe(2.0);
      expect(getTrack(0).clipIds).not.toContain("c1");
      expect(getTrack(1).clipIds).toContain("c1");
    });
  });

  describe("splitClip", () => {
    it("splits a clip at a given time", () => {
      useDawStore.getState().addTrack(makeTrack({ id: "t1" }));
      useDawStore.getState().addClip(
        makeClip({
          id: "c1",
          trackId: "t1",
          startTime: 2,
          sourceOffset: 0,
          duration: 6,
        }),
      );
      const newId = useDawStore.getState().splitClip("c1", 5);
      expect(newId).toBeDefined();

      const left = getClip("c1");
      const right = getClip(newId as string);

      // Left clip: startTime=2, duration=3 (5-2)
      expect(left.startTime).toBe(2);
      expect(left.duration).toBe(3);
      expect(left.sourceOffset).toBe(0);

      // Right clip: startTime=5, duration=3 (6-3), sourceOffset=3
      expect(right.startTime).toBe(5);
      expect(right.duration).toBe(3);
      expect(right.sourceOffset).toBe(3);
      expect(right.trackId).toBe("t1");
    });

    it("returns undefined if split point is outside clip", () => {
      useDawStore.getState().addTrack(makeTrack({ id: "t1" }));
      useDawStore.getState().addClip(
        makeClip({
          id: "c1",
          trackId: "t1",
          startTime: 2,
          duration: 4,
        }),
      );
      expect(useDawStore.getState().splitClip("c1", 10)).toBeUndefined();
      expect(useDawStore.getState().splitClip("c1", 1)).toBeUndefined();
    });
  });

  describe("trimClip", () => {
    it("trims clip start (moves startTime forward, adjusts sourceOffset)", () => {
      useDawStore.getState().addTrack(makeTrack({ id: "t1" }));
      useDawStore.getState().addClip(
        makeClip({
          id: "c1",
          trackId: "t1",
          startTime: 2,
          sourceOffset: 0,
          duration: 6,
        }),
      );
      useDawStore.getState().trimClip("c1", 4, undefined);
      const clip = getClip("c1");
      expect(clip.startTime).toBe(4);
      expect(clip.sourceOffset).toBe(2);
      expect(clip.duration).toBe(4);
    });

    it("trims clip end", () => {
      useDawStore.getState().addTrack(makeTrack({ id: "t1" }));
      useDawStore.getState().addClip(
        makeClip({
          id: "c1",
          trackId: "t1",
          startTime: 2,
          sourceOffset: 0,
          duration: 6,
        }),
      );
      useDawStore.getState().trimClip("c1", undefined, 5);
      const clip = getClip("c1");
      expect(clip.startTime).toBe(2);
      expect(clip.duration).toBe(3);
    });
  });

  describe("duplicateClip", () => {
    it("creates a new clip placed right after the original", () => {
      useDawStore.getState().addTrack(makeTrack({ id: "t1" }));
      useDawStore
        .getState()
        .addClip(
          makeClip({ id: "c1", trackId: "t1", startTime: 2, duration: 4 }),
        );
      const newId = useDawStore.getState().duplicateClip("c1");
      expect(newId).toBeDefined();
      const dup = getClip(newId as string);
      expect(dup.startTime).toBe(6); // 2 + 4
      expect(dup.duration).toBe(4);
      expect(dup.sourceId).toBe("source-1");
      expect(dup.trackId).toBe("t1");
    });
  });

  describe("selection", () => {
    it("selects and deselects tracks", () => {
      useDawStore.getState().setSelectedTrackIds(["t1", "t2"]);
      expect(useDawStore.getState().selectedTrackIds).toEqual(["t1", "t2"]);
      useDawStore.getState().setSelectedTrackIds([]);
      expect(useDawStore.getState().selectedTrackIds).toEqual([]);
    });

    it("selects and deselects clips", () => {
      useDawStore.getState().setSelectedClipIds(["c1"]);
      expect(useDawStore.getState().selectedClipIds).toEqual(["c1"]);
    });
  });
});

describe("arrangementQuery", () => {
