describe("Track commands", () => {
  beforeEach(() => {
    useDawStore.setState({
      tracks: [],
      clips: {},
      selectedTrackIds: [],
      selectedClipIds: [],
    });
  });

  describe("AddTrackCommand", () => {
    it("execute adds the track to the store", () => {
      const track = makeTrack({ id: "t1" });
      const cmd = new AddTrackCommand(track);
      cmd.execute();
      expect(getStore().tracks).toHaveLength(1);
      expect(getStore().tracks[0]?.id).toBe("t1");
    });

    it("execute inserts at a specific index", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addTrack(makeTrack({ id: "t3" }));
      const cmd = new AddTrackCommand(makeTrack({ id: "t2" }), 1);
      cmd.execute();
      const ids = getStore().tracks.map((t) => t.id);
      expect(ids).toEqual(["t1", "t2", "t3"]);
    });

    it("undo removes the track", () => {
      const track = makeTrack({ id: "t1" });
      const cmd = new AddTrackCommand(track);
      cmd.execute();
      cmd.undo();
      expect(getStore().tracks).toHaveLength(0);
    });

    it("has type add-track", () => {
      const cmd = new AddTrackCommand(makeTrack());
      expect(cmd.type).toBe("add-track");
    });

    it("serializes track and index", () => {
      const track = makeTrack({ id: "t1" });
      const cmd = new AddTrackCommand(track, 2);
      const data = cmd.serialize();
      expect(data["track"]).toEqual(track);
      expect(data["index"]).toBe(2);
    });
  });

  describe("RemoveTrackCommand", () => {
    it("execute removes the track", () => {
      const track = makeTrack({ id: "t1" });
      getStore().addTrack(track);
      const cmd = new RemoveTrackCommand("t1");
      cmd.execute();
      expect(getStore().tracks).toHaveLength(0);
    });

    it("undo restores the track at its original index", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addTrack(makeTrack({ id: "t2" }));
      getStore().addTrack(makeTrack({ id: "t3" }));

      const cmd = new RemoveTrackCommand("t2");
      cmd.execute();
      expect(getStore().tracks).toHaveLength(2);

      cmd.undo();
      expect(getStore().tracks).toHaveLength(3);
      expect(getStore().tracks[1]?.id).toBe("t2");
    });

    it("undo restores associated clips", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(makeClip({ id: "c1", trackId: "t1" }));
      getStore().addClip(makeClip({ id: "c2", trackId: "t1" }));

      const cmd = new RemoveTrackCommand("t1");
      cmd.execute();
      expect(getStore().clips["c1"]).toBeUndefined();

      cmd.undo();
      expect(getStore().clips["c1"]).toBeDefined();
      expect(getStore().clips["c2"]).toBeDefined();
    });

    it("has type remove-track", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      const cmd = new RemoveTrackCommand("t1");
      expect(cmd.type).toBe("remove-track");
    });

    it("serializes the track id", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      const cmd = new RemoveTrackCommand("t1");
      const data = cmd.serialize();
      expect(data["trackId"]).toBe("t1");
    });
  });

  describe("UpdateTrackCommand", () => {
    it("execute applies the patch", () => {
      getStore().addTrack(makeTrack({ id: "t1", name: "Old" }));
      const cmd = new UpdateTrackCommand("t1", { name: "New" });
      cmd.execute();
      expect(getStore().tracks[0]?.name).toBe("New");
    });

    it("undo restores the old values", () => {
      getStore().addTrack(makeTrack({ id: "t1", name: "Old", muted: false }));
      const cmd = new UpdateTrackCommand("t1", { name: "New", muted: true });
      cmd.execute();
      cmd.undo();
      expect(getStore().tracks[0]?.name).toBe("Old");
      expect(getStore().tracks[0]?.muted).toBe(false);
    });

    it("has type update-track", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      const cmd = new UpdateTrackCommand("t1", { name: "X" });
      expect(cmd.type).toBe("update-track");
    });

    it("serializes id and both patches", () => {
      getStore().addTrack(makeTrack({ id: "t1", name: "Old" }));
      const cmd = new UpdateTrackCommand("t1", { name: "New" });
      const data = cmd.serialize();
      expect(data["trackId"]).toBe("t1");
      expect(data["newPatch"]).toEqual({ name: "New" });
    });
  });

  describe("ReorderTrackCommand", () => {
    it("execute moves track to target index", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addTrack(makeTrack({ id: "t2" }));
      getStore().addTrack(makeTrack({ id: "t3" }));

      const cmd = new ReorderTrackCommand("t3", 0);
      cmd.execute();
      const ids = getStore().tracks.map((t) => t.id);
      expect(ids).toEqual(["t3", "t1", "t2"]);
    });

    it("undo moves track back to original index", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addTrack(makeTrack({ id: "t2" }));
      getStore().addTrack(makeTrack({ id: "t3" }));

      const cmd = new ReorderTrackCommand("t3", 0);
      cmd.execute();
      cmd.undo();
      const ids = getStore().tracks.map((t) => t.id);
      expect(ids).toEqual(["t1", "t2", "t3"]);
    });

    it("has type reorder-track", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      const cmd = new ReorderTrackCommand("t1", 0);
      expect(cmd.type).toBe("reorder-track");
    });

    it("serializes id, fromIndex, and toIndex", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addTrack(makeTrack({ id: "t2" }));
      const cmd = new ReorderTrackCommand("t2", 0);
      const data = cmd.serialize();
      expect(data["trackId"]).toBe("t2");
      expect(data["toIndex"]).toBe(0);
    });
  });

  describe("AddClipCommand", () => {
    it("execute adds the clip", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      const clip = makeClip({ id: "c1", trackId: "t1" });
      const cmd = new AddClipCommand(clip);
      cmd.execute();
      expect(getStore().clips["c1"]).toBeDefined();
      expect(getStore().tracks[0]?.clipIds).toContain("c1");
    });

    it("undo removes the clip", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      const clip = makeClip({ id: "c1", trackId: "t1" });
      const cmd = new AddClipCommand(clip);
      cmd.execute();
      cmd.undo();
      expect(getStore().clips["c1"]).toBeUndefined();
    });

    it("has type add-clip", () => {
      const cmd = new AddClipCommand(makeClip());
      expect(cmd.type).toBe("add-clip");
    });

    it("serializes the clip", () => {
      const clip = makeClip({ id: "c1" });
      const cmd = new AddClipCommand(clip);
      expect(cmd.serialize()["clip"]).toEqual(clip);
    });
  });

  describe("RemoveClipCommand", () => {
    it("execute removes the clip", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(makeClip({ id: "c1", trackId: "t1" }));
      const cmd = new RemoveClipCommand("c1");
      cmd.execute();
      expect(getStore().clips["c1"]).toBeUndefined();
    });

    it("undo restores the clip", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      const clip = makeClip({ id: "c1", trackId: "t1" });
      getStore().addClip(clip);
      const cmd = new RemoveClipCommand("c1");
      cmd.execute();
      cmd.undo();
      expect(getStore().clips["c1"]).toBeDefined();
      expect(getStore().tracks[0]?.clipIds).toContain("c1");
    });

    it("has type remove-clip", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(makeClip({ id: "c1", trackId: "t1" }));
      const cmd = new RemoveClipCommand("c1");
      expect(cmd.type).toBe("remove-clip");
    });

    it("serializes the clip id", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(makeClip({ id: "c1", trackId: "t1" }));
      const cmd = new RemoveClipCommand("c1");
      expect(cmd.serialize()["clipId"]).toBe("c1");
    });
  });

  describe("MoveClipCommand", () => {
    it("execute moves the clip to a new time", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(makeClip({ id: "c1", trackId: "t1", startTime: 0 }));
      const cmd = new MoveClipCommand("c1", 5);
      cmd.execute();
      expect(getStore().clips["c1"]?.startTime).toBe(5);
    });

    it("execute moves the clip to a different track", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addTrack(makeTrack({ id: "t2" }));
      getStore().addClip(makeClip({ id: "c1", trackId: "t1", startTime: 0 }));
      const cmd = new MoveClipCommand("c1", 3, "t2");
      cmd.execute();
      expect(getStore().clips["c1"]?.startTime).toBe(3);
      expect(getStore().clips["c1"]?.trackId).toBe("t2");
    });

    it("undo restores original position and track", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addTrack(makeTrack({ id: "t2" }));
      getStore().addClip(makeClip({ id: "c1", trackId: "t1", startTime: 2 }));
      const cmd = new MoveClipCommand("c1", 7, "t2");
      cmd.execute();
      cmd.undo();
      expect(getStore().clips["c1"]?.startTime).toBe(2);
      expect(getStore().clips["c1"]?.trackId).toBe("t1");
    });

    it("has type move-clip", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(makeClip({ id: "c1", trackId: "t1", startTime: 0 }));
      const cmd = new MoveClipCommand("c1", 5);
      expect(cmd.type).toBe("move-clip");
    });

    it("serializes clip id, old and new positions", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(makeClip({ id: "c1", trackId: "t1", startTime: 2 }));
      const cmd = new MoveClipCommand("c1", 5, "t2");
      const data = cmd.serialize();
      expect(data["clipId"]).toBe("c1");
      expect(data["newStartTime"]).toBe(5);
      expect(data["newTrackId"]).toBe("t2");
    });
  });

  describe("SplitClipCommand", () => {
    it("execute splits the clip at the given time", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(
        makeClip({
          id: "c1",
          trackId: "t1",
          startTime: 2,
          sourceOffset: 0,
          duration: 6,
        }),
      );
      const cmd = new SplitClipCommand("c1", 5);
      cmd.execute();

      const left = getStore().clips["c1"];
      expect(left?.duration).toBe(3);
      expect(left?.startTime).toBe(2);

      // The right clip should exist with the generated id
      const rightId = cmd.rightClipId();
      expect(rightId).toBeDefined();
      if (rightId !== undefined) {
        const right = getStore().clips[rightId];
        expect(right?.startTime).toBe(5);
        expect(right?.duration).toBe(3);
        expect(right?.sourceOffset).toBe(3);
      }
    });

    it("undo rejoins the clip (restores original, removes right)", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(
        makeClip({
          id: "c1",
          trackId: "t1",
          startTime: 2,
          sourceOffset: 0,
          duration: 6,
        }),
      );
      const cmd = new SplitClipCommand("c1", 5);
      cmd.execute();
      const rightId = cmd.rightClipId();

      cmd.undo();
      const restored = getStore().clips["c1"];
      expect(restored?.duration).toBe(6);
      expect(restored?.startTime).toBe(2);
      expect(restored?.sourceOffset).toBe(0);

      if (rightId !== undefined) {
        expect(getStore().clips[rightId]).toBeUndefined();
      }
    });

    it("has type split-clip", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(makeClip({ id: "c1", trackId: "t1" }));
      const cmd = new SplitClipCommand("c1", 2);
      expect(cmd.type).toBe("split-clip");
    });

    it("serializes clip id and split time", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(makeClip({ id: "c1", trackId: "t1" }));
      const cmd = new SplitClipCommand("c1", 2);
      const data = cmd.serialize();
      expect(data["clipId"]).toBe("c1");
      expect(data["atTime"]).toBe(2);
    });
  });

  describe("TrimClipCommand", () => {
    it("execute trims the clip start", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(
        makeClip({
          id: "c1",
          trackId: "t1",
          startTime: 2,
          sourceOffset: 0,
          duration: 6,
        }),
      );
      const cmd = new TrimClipCommand("c1", 4, undefined);
      cmd.execute();
      const clip = getStore().clips["c1"];
      expect(clip?.startTime).toBe(4);
      expect(clip?.sourceOffset).toBe(2);
      expect(clip?.duration).toBe(4);
    });

    it("execute trims the clip end", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(
        makeClip({
          id: "c1",
          trackId: "t1",
          startTime: 2,
          sourceOffset: 0,
          duration: 6,
        }),
      );
      const cmd = new TrimClipCommand("c1", undefined, 5);
      cmd.execute();
      const clip = getStore().clips["c1"];
      expect(clip?.startTime).toBe(2);
      expect(clip?.duration).toBe(3);
    });

    it("undo restores the original clip state", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(
        makeClip({
          id: "c1",
          trackId: "t1",
          startTime: 2,
          sourceOffset: 0,
          duration: 6,
        }),
      );
      const cmd = new TrimClipCommand("c1", 4, 7);
      cmd.execute();
      cmd.undo();
      const clip = getStore().clips["c1"];
      expect(clip?.startTime).toBe(2);
      expect(clip?.sourceOffset).toBe(0);
      expect(clip?.duration).toBe(6);
    });

    it("has type trim-clip", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(makeClip({ id: "c1", trackId: "t1" }));
      const cmd = new TrimClipCommand("c1", 1, undefined);
      expect(cmd.type).toBe("trim-clip");
    });

    it("serializes clip id and trim values", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(makeClip({ id: "c1", trackId: "t1" }));
      const cmd = new TrimClipCommand("c1", 1, 3);
      const data = cmd.serialize();
      expect(data["clipId"]).toBe("c1");
      expect(data["newStart"]).toBe(1);
      expect(data["newEnd"]).toBe(3);
    });
  });

  describe("DuplicateClipCommand", () => {
    it("execute duplicates the clip", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(
        makeClip({ id: "c1", trackId: "t1", startTime: 2, duration: 4 }),
      );
      const cmd = new DuplicateClipCommand("c1");
      cmd.execute();

      const newId = cmd.duplicatedClipId();
      expect(newId).toBeDefined();
      if (newId !== undefined) {
        const dup = getStore().clips[newId];
        expect(dup?.startTime).toBe(6);
        expect(dup?.duration).toBe(4);
      }
    });

    it("undo removes the duplicated clip", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(
        makeClip({ id: "c1", trackId: "t1", startTime: 2, duration: 4 }),
      );
      const cmd = new DuplicateClipCommand("c1");
      cmd.execute();
      const newId = cmd.duplicatedClipId();

      cmd.undo();
      if (newId !== undefined) {
        expect(getStore().clips[newId]).toBeUndefined();
      }
      // Original should still exist
      expect(getStore().clips["c1"]).toBeDefined();
    });

    it("has type duplicate-clip", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(makeClip({ id: "c1", trackId: "t1" }));
      const cmd = new DuplicateClipCommand("c1");
      expect(cmd.type).toBe("duplicate-clip");
    });

    it("serializes the source clip id", () => {
      getStore().addTrack(makeTrack({ id: "t1" }));
      getStore().addClip(makeClip({ id: "c1", trackId: "t1" }));
      const cmd = new DuplicateClipCommand("c1");
      const data = cmd.serialize();
      expect(data["clipId"]).toBe("c1");
    });
  });
});

import { describe, it, expect, vi } from "vitest";
import type { TrackModel, ClipModel } from "@state/track/types";
import {
  renderArrangement,
  type ArrangementViewState,
  type RenderContext,
} from "./arrangement-renderer";

// -- Helpers ------------------------------------------------------------------

type MockCtx = {
  fillRect: ReturnType<typeof vi.fn>;
  strokeRect: ReturnType<typeof vi.fn>;
  fillText: ReturnType<typeof vi.fn>;
  beginPath: ReturnType<typeof vi.fn>;
  moveTo: ReturnType<typeof vi.fn>;
  lineTo: ReturnType<typeof vi.fn>;
  stroke: ReturnType<typeof vi.fn>;
  save: ReturnType<typeof vi.fn>;
  restore: ReturnType<typeof vi.fn>;
  clearRect: ReturnType<typeof vi.fn>;
  rect: ReturnType<typeof vi.fn>;
  clip: ReturnType<typeof vi.fn>;
  measureText: ReturnType<typeof vi.fn>;
  fillStyle: string;
  strokeStyle: string;
  lineWidth: number;
  font: string;
  textBaseline: CanvasTextBaseline;
  textAlign: CanvasTextAlign;
  globalAlpha: number;
};

function createMockCtx(): MockCtx {
  return {
    fillRect: vi.fn(),
    strokeRect: vi.fn(),
    fillText: vi.fn(),
    beginPath: vi.fn(),
    moveTo: vi.fn(),
    lineTo: vi.fn(),
    stroke: vi.fn(),
    save: vi.fn(),
    restore: vi.fn(),
    clearRect: vi.fn(),
    rect: vi.fn(),
    clip: vi.fn(),
    measureText: vi.fn().mockReturnValue({ width: 40 }),
    fillStyle: "",
    strokeStyle: "",
    lineWidth: 0,
    font: "",
    textBaseline: "alphabetic",
    textAlign: "start",
    globalAlpha: 1,
  };
}

function makeTrack(overrides: Partial<TrackModel> = {}): TrackModel {
  return {
    id: "track-1",
    name: "Track 1",
    type: "audio",
    color: "#0066ff",
    muted: false,
    solo: false,
    armed: false,
    volume: 1,
    pan: 0,
    clipIds: [],
    ...overrides,
  };
}

function makeClip(overrides: Partial<ClipModel> = {}): ClipModel {
  return {
    id: "clip-1",
    trackId: "track-1",
    sourceId: "src-1",
    startTime: 0,
    sourceOffset: 0,
    duration: 2,
    gain: 1,
    fadeIn: 0,
    fadeOut: 0,
    name: "Clip 1",
    ...overrides,
  };
}

const defaultView: ArrangementViewState = {
  scrollX: 0,
  scrollY: 0,
  pixelsPerSecond: 100,
  trackHeight: 64,
  headerWidth: 160,
};

function makeRenderContext(
  overrides: Partial<Omit<RenderContext, "ctx">> = {},
): { rc: RenderContext; mock: MockCtx } {
  const mock = createMockCtx();
  const rc: RenderContext = {
    ctx: mock as unknown as CanvasRenderingContext2D,
    width: 800,
    height: 400,
    view: defaultView,
    tracks: [],
    clips: {},
    selectedClipIds: [],
    cursorSeconds: 0,
    bpm: 120,
    ...overrides,
  };
  return { rc, mock };
}

// -- Tests --------------------------------------------------------------------

describe("arrangement-renderer", () => {
  describe("renderArrangement", () => {
    it("fills background with gray-900", () => {
      const { rc, mock } = makeRenderContext();
      renderArrangement(rc);
      expect(mock.fillRect).toHaveBeenCalledWith(0, 0, 800, 400);
    });

    it("draws the time ruler area", () => {
      const { rc, mock } = makeRenderContext();
      renderArrangement(rc);
      expect(mock.fillRect.mock.calls.length).toBeGreaterThan(1);
    });

    it("draws vertical grid lines at beat positions", () => {
      const { rc, mock } = makeRenderContext({ bpm: 120 });
      renderArrangement(rc);
      expect(mock.moveTo.mock.calls.length).toBeGreaterThan(0);
      expect(mock.lineTo.mock.calls.length).toBeGreaterThan(0);
    });

    it("draws thicker lines on bar boundaries (every 4 beats)", () => {
      const { rc, mock } = makeRenderContext({ bpm: 120 });
      renderArrangement(rc);
      expect(mock.save).toHaveBeenCalled();
      expect(mock.restore).toHaveBeenCalled();
    });

    it("draws track lanes as horizontal bands", () => {
      const tracks = [
        makeTrack({ id: "t1", name: "Track 1" }),
        makeTrack({ id: "t2", name: "Track 2" }),
      ];
      const { rc, mock } = makeRenderContext({ tracks });
      renderArrangement(rc);
      expect(mock.stroke.mock.calls.length).toBeGreaterThan(0);
    });

    it("draws track headers with name and color strip", () => {
      const tracks = [
        makeTrack({ id: "t1", name: "Guitar", color: "#ff2d6f" }),
      ];
      const { rc, mock } = makeRenderContext({ tracks });
      renderArrangement(rc);

      const drawnTexts = mock.fillText.mock.calls.map(
        ([text]: [string]) => text,
      );
      expect(drawnTexts).toContain("Guitar");
    });

    it("draws mute indicator on muted tracks", () => {
      const tracks = [makeTrack({ id: "t1", name: "Bass", muted: true })];
      const { rc, mock } = makeRenderContext({ tracks });
      renderArrangement(rc);

      const drawnTexts = mock.fillText.mock.calls.map(
        ([text]: [string]) => text,
      );
      expect(drawnTexts).toContain("M");
    });

    it("draws solo indicator on solo tracks", () => {
      const tracks = [makeTrack({ id: "t1", name: "Lead", solo: true })];
      const { rc, mock } = makeRenderContext({ tracks });
      renderArrangement(rc);

      const drawnTexts = mock.fillText.mock.calls.map(
        ([text]: [string]) => text,
      );
      expect(drawnTexts).toContain("S");
    });

    it("draws clips as rectangles on the timeline", () => {
      const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
      const clips: Record<string, ClipModel> = {
        c1: makeClip({
          id: "c1",
          trackId: "t1",
          startTime: 1,
          duration: 2,
        }),
      };
      const { rc, mock } = makeRenderContext({ tracks, clips });
      renderArrangement(rc);

      // At pps=100 and startTime=1 with headerWidth=160:
      // x = 160 + (1 - 0) * 100 = 260, width = 2 * 100 = 200
      expect(mock.fillRect.mock.calls).toContainEqual(
        expect.arrayContaining([
          260,
          expect.any(Number),
          200,
          expect.any(Number),
        ]),
      );
    });

    it("draws clip name label", () => {
      const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
      const clips: Record<string, ClipModel> = {
        c1: makeClip({ id: "c1", trackId: "t1", name: "Vocal Take" }),
      };
      const { rc, mock } = makeRenderContext({ tracks, clips });
      renderArrangement(rc);

      const drawnTexts = mock.fillText.mock.calls.map(
        ([text]: [string]) => text,
      );
      expect(drawnTexts).toContain("Vocal Take");
    });

    it("draws selected clips with white border", () => {
      const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
      const clips: Record<string, ClipModel> = {
        c1: makeClip({ id: "c1", trackId: "t1" }),
      };
      const { rc, mock } = makeRenderContext({
        tracks,
        clips,
        selectedClipIds: ["c1"],
      });
      renderArrangement(rc);
      expect(mock.strokeRect).toHaveBeenCalled();
    });

    it("draws the playhead as a vertical red line", () => {
      const { rc, mock } = makeRenderContext({ cursorSeconds: 2 });
      renderArrangement(rc);

      // Playhead at 2s with pps=100, headerWidth=160: x = 160 + 2*100 = 360
      const playheadMoves = (
        mock.moveTo.mock.calls as [number, number][]
      ).filter(([x]) => x === 360);
      expect(playheadMoves.length).toBeGreaterThan(0);

      const playheadLines = (
        mock.lineTo.mock.calls as [number, number][]
      ).filter(([x]) => x === 360);
      expect(playheadLines.length).toBeGreaterThan(0);
    });

    it("draws bar numbers in the time ruler", () => {
      const { rc, mock } = makeRenderContext({ bpm: 120 });
      renderArrangement(rc);

      const drawnTexts = mock.fillText.mock.calls.map(
        ([text]: [string]) => text,
      );
      expect(drawnTexts).toContain("1");
    });

    it("respects scrollX offset for grid and clips", () => {
      const view: ArrangementViewState = {
        ...defaultView,
        scrollX: 2,
      };
      const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
      const clips: Record<string, ClipModel> = {
        c1: makeClip({
          id: "c1",
          trackId: "t1",
          startTime: 3,
          duration: 1,
        }),
      };
      const { rc, mock } = makeRenderContext({ view, tracks, clips });
      renderArrangement(rc);

      // Clip at startTime=3 with scrollX=2, pps=100, headerWidth=160:
      // x = 160 + (3 - 2) * 100 = 260
      expect(mock.fillRect.mock.calls).toContainEqual(
        expect.arrayContaining([
          260,
          expect.any(Number),
          100,
          expect.any(Number),
        ]),
      );
    });

    it("respects scrollY offset for tracks", () => {
      const view: ArrangementViewState = {
        ...defaultView,
        scrollY: 30,
      };
      const tracks = [makeTrack({ id: "t1", name: "Shifted Track" })];
      const { rc, mock } = makeRenderContext({ view, tracks });
      renderArrangement(rc);

      const shiftedCall = mock.fillText.mock.calls.find(
        ([text]: [string]) => text === "Shifted Track",
      );
      expect(shiftedCall).toBeDefined();
    });

    it("adjusts grid density when zoomed out", () => {
      const view: ArrangementViewState = {
        ...defaultView,
        pixelsPerSecond: 20,
      };
      const { rc, mock } = makeRenderContext({ view });
      renderArrangement(rc);
      expect(mock.stroke).toHaveBeenCalled();
    });

    it("does not crash with empty tracks and clips", () => {
      const { rc } = makeRenderContext({ tracks: [], clips: {} });
      expect(() => {
        renderArrangement(rc);
      }).not.toThrow();
    });

    it("does not crash when clip references missing track", () => {
      const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
      const clips: Record<string, ClipModel> = {
        c1: makeClip({ id: "c1", trackId: "t-missing" }),
      };
      const { rc } = makeRenderContext({ tracks, clips });
      expect(() => {
        renderArrangement(rc);
      }).not.toThrow();
    });
  });
});

import { describe, it, expect } from "vitest";
import type { TrackModel, ClipModel } from "@state/track/types";
import type { ArrangementViewState } from "./arrangement-renderer";
import { hitTest, snapToGrid, xToSeconds } from "./hit-test";

const defaultView: ArrangementViewState = {
  scrollX: 0,
  scrollY: 0,
  pixelsPerSecond: 100,
  trackHeight: 64,
  headerWidth: 160,
};

function makeTrack(overrides: Partial<TrackModel> = {}): TrackModel {
  return {
    id: "t1",
    name: "Track 1",
    type: "audio",
    color: "#0066ff",
    muted: false,
    solo: false,
    armed: false,
    volume: 1,
    pan: 0,
    clipIds: [],
    ...overrides,
  };
}

function makeClip(overrides: Partial<ClipModel> = {}): ClipModel {
  return {
    id: "c1",
    trackId: "t1",
    sourceId: "src-1",
    startTime: 0,
    sourceOffset: 0,
    duration: 2,
    gain: 1,
    fadeIn: 0,
    fadeOut: 0,
    name: "Clip 1",
    ...overrides,
  };
}

describe("snapToGrid", () => {
  it("snaps to quarter note grid at 120 BPM", () => {
    // secPerBeat = 0.5 at 120 BPM
    expect(snapToGrid(0.3, 120, "1/4")).toBeCloseTo(0.5);
    expect(snapToGrid(0.7, 120, "1/4")).toBeCloseTo(0.5);
    expect(snapToGrid(0.8, 120, "1/4")).toBeCloseTo(1.0);
  });

  it("snaps to eighth note grid", () => {
    // secPerBeat/2 = 0.25 at 120 BPM
    expect(snapToGrid(0.2, 120, "1/8")).toBeCloseTo(0.25);
    expect(snapToGrid(0.1, 120, "1/8")).toBeCloseTo(0.0);
  });

  it("snaps to sixteenth note grid", () => {
    // secPerBeat/4 = 0.125 at 120 BPM
    expect(snapToGrid(0.1, 120, "1/16")).toBeCloseTo(0.125);
  });

  it("snaps to bar grid", () => {
    // 4 beats * 0.5 = 2 seconds per bar at 120 BPM
    expect(snapToGrid(1.5, 120, "1-bar")).toBeCloseTo(2.0);
    expect(snapToGrid(0.5, 120, "1-bar")).toBeCloseTo(0.0);
  });
});

describe("xToSeconds", () => {
  it("converts pixel position to seconds", () => {
    // x=260, headerWidth=160, pps=100, scrollX=0
    // (260 - 160) / 100 = 1.0
    expect(xToSeconds(260, defaultView)).toBeCloseTo(1.0);
  });

  it("accounts for scrollX", () => {
    const view = { ...defaultView, scrollX: 2 };
    // (260 - 160) / 100 + 2 = 3.0
    expect(xToSeconds(260, view)).toBeCloseTo(3.0);
  });
});

describe("hitTest", () => {
  it("returns ruler hit when clicking in ruler area", () => {
    const result = hitTest(200, 10, defaultView, [], {});
    expect(result.kind).toBe("ruler");
    if (result.kind === "ruler") {
      expect(result.timeSeconds).toBeCloseTo(0.4);
    }
  });

  it("returns track-header hit when clicking in header area", () => {
    const tracks = [makeTrack({ id: "t1" })];
    const result = hitTest(80, 50, defaultView, tracks, {});
    expect(result.kind).toBe("track-header");
    if (result.kind === "track-header") {
      expect(result.trackId).toBe("t1");
      expect(result.trackIndex).toBe(0);
    }
  });

  it("returns none when clicking header with no track", () => {
    const result = hitTest(80, 500, defaultView, [], {});
    expect(result.kind).toBe("none");
  });

  it("returns clip-body hit when clicking a clip center", () => {
    const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
    const clips: Record<string, ClipModel> = {
      c1: makeClip({ id: "c1", trackId: "t1", startTime: 1, duration: 2 }),
    };
    // Clip starts at x = 160 + 1*100 = 260, width = 200
    // Click at center: x = 360
    const result = hitTest(360, 50, defaultView, tracks, clips);
    expect(result.kind).toBe("clip-body");
    if (result.kind === "clip-body") {
      expect(result.clipId).toBe("c1");
    }
  });

  it("returns clip-left-edge when clicking near left edge", () => {
    const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
    const clips: Record<string, ClipModel> = {
      c1: makeClip({ id: "c1", trackId: "t1", startTime: 1, duration: 2 }),
    };
    // Clip starts at x=260, click at x=263 (within 8px handle)
    const result = hitTest(263, 50, defaultView, tracks, clips);
    expect(result.kind).toBe("clip-left-edge");
  });

  it("returns clip-right-edge when clicking near right edge", () => {
    const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
    const clips: Record<string, ClipModel> = {
      c1: makeClip({ id: "c1", trackId: "t1", startTime: 1, duration: 2 }),
    };
    // Clip ends at x = 260 + 200 = 460, click at x=455 (within 8px handle)
    const result = hitTest(455, 50, defaultView, tracks, clips);
    expect(result.kind).toBe("clip-right-edge");
  });

  it("returns empty-lane when clicking timeline without clip", () => {
    const tracks = [makeTrack({ id: "t1" })];
    const result = hitTest(300, 50, defaultView, tracks, {});
    expect(result.kind).toBe("empty-lane");
    if (result.kind === "empty-lane") {
      expect(result.trackId).toBe("t1");
    }
  });

  it("accounts for scrollY offset", () => {
    const tracks = [makeTrack({ id: "t1" }), makeTrack({ id: "t2" })];
    const view = { ...defaultView, scrollY: 64 };
    // With scrollY=64, track t2 (index 1) is at y = 24 + 1*64 - 64 = 24
    // Click at y=50 should hit track t2
    const result = hitTest(80, 50, view, tracks, {});
    expect(result.kind).toBe("track-header");
    if (result.kind === "track-header") {
      expect(result.trackId).toBe("t2");
    }
  });
});

import { describe, it, expect, beforeEach } from "vitest";
import { renderHook, act } from "@testing-library/react";
import { useDawStore } from "@state/store";
import type { TrackModel, ClipModel } from "@state/track/types";
import { sharedUndoManager } from "@state/undo";
import { useArrangementInteractions } from "./use-arrangement-interactions";
import type { ArrangementViewState } from "./arrangement-renderer";

const defaultView: ArrangementViewState = {
  scrollX: 0,
  scrollY: 0,
  pixelsPerSecond: 100,
  trackHeight: 64,
  headerWidth: 160,
};

function makeTrack(overrides: Partial<TrackModel> = {}): TrackModel {
  return {
    id: "t1",
    name: "Track 1",
    type: "audio",
    color: "#0066ff",
    muted: false,
    solo: false,
    armed: false,
    volume: 1,
    pan: 0,
    clipIds: [],
    ...overrides,
  };
}

function makeClip(overrides: Partial<ClipModel> = {}): ClipModel {
  return {
    id: "c1",
    trackId: "t1",
    sourceId: "src-1",
    startTime: 1,
    sourceOffset: 0,
    duration: 2,
    gain: 1,
    fadeIn: 0,
    fadeOut: 0,
    name: "Clip 1",
    ...overrides,
  };
}

function mockCanvasTarget(): HTMLCanvasElement {
  return {
    getBoundingClientRect: () => ({
      left: 0,
      top: 0,
      width: 800,
      height: 400,
      right: 800,
      bottom: 400,
      x: 0,
      y: 0,
      toJSON: (): void => {},
    }),
    setPointerCapture: (): void => {},
    releasePointerCapture: (): void => {},
  } as unknown as HTMLCanvasElement;
}

function mockPointerEvent(
  overrides: Partial<React.PointerEvent<HTMLCanvasElement>> = {},
): React.PointerEvent<HTMLCanvasElement> {
  return {
    clientX: 0,
    clientY: 0,
    shiftKey: false,
    ctrlKey: false,
    metaKey: false,
    pointerId: 1,
    currentTarget: mockCanvasTarget(),
    preventDefault: (): void => {},
    ...overrides,
  } as unknown as React.PointerEvent<HTMLCanvasElement>;
}

function mockMouseEvent(
  overrides: Partial<React.MouseEvent<HTMLCanvasElement>> = {},
): React.MouseEvent<HTMLCanvasElement> {
  return {
    clientX: 0,
    clientY: 0,
    shiftKey: false,
    ctrlKey: false,
    metaKey: false,
    currentTarget: mockCanvasTarget(),
    preventDefault: (): void => {},
    ...overrides,
  } as unknown as React.MouseEvent<HTMLCanvasElement>;
}

describe("useArrangementInteractions", () => {
  beforeEach(() => {
    useDawStore.setState({
      tracks: [],
      clips: {},
      selectedTrackIds: [],
      selectedClipIds: [],
      cursorSeconds: 0,
      bpm: 120,
    });
    sharedUndoManager.clear();
  });

  it("selects clip on pointerDown on clip body", () => {
    const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
    const clips: Record<string, ClipModel> = {
      c1: makeClip({ id: "c1", trackId: "t1", startTime: 1, duration: 2 }),
    };
    useDawStore.setState({ tracks, clips });

    const { result } = renderHook(() =>
      useArrangementInteractions(defaultView, "1/4"),
    );

    act(() => {
      result.current.onPointerDown(
        mockPointerEvent({ clientX: 360, clientY: 50 }),
      );
    });

    expect(useDawStore.getState().selectedClipIds).toContain("c1");
  });

  it("deselects clips when clicking empty lane without shift", () => {
    useDawStore.setState({
      tracks: [makeTrack({ id: "t1" })],
      selectedClipIds: ["c1"],
    });

    const { result } = renderHook(() =>
      useArrangementInteractions(defaultView, "1/4"),
    );

    act(() => {
      result.current.onPointerDown(
        mockPointerEvent({ clientX: 500, clientY: 50 }),
      );
    });

    expect(useDawStore.getState().selectedClipIds).toEqual([]);
  });

  it("sets cursor on ruler click", () => {
    const { result } = renderHook(() =>
      useArrangementInteractions(defaultView, "1/4"),
    );

    // Click in ruler area: y < 24, x = 260
    // Time = (260 - 160) / 100 = 1.0
    act(() => {
      result.current.onPointerDown(
        mockPointerEvent({ clientX: 260, clientY: 10 }),
      );
    });

    expect(useDawStore.getState().cursorSeconds).toBeCloseTo(1.0);
  });

  it("selects track on header click", () => {
    useDawStore.setState({
      tracks: [makeTrack({ id: "t1" })],
    });

    const { result } = renderHook(() =>
      useArrangementInteractions(defaultView, "1/4"),
    );

    act(() => {
      result.current.onPointerDown(
        mockPointerEvent({ clientX: 80, clientY: 50 }),
      );
    });

    expect(useDawStore.getState().selectedTrackIds).toContain("t1");
  });

  it("splits clip on double-click and pushes undo", () => {
    const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
    const clips: Record<string, ClipModel> = {
      c1: makeClip({ id: "c1", trackId: "t1", startTime: 1, duration: 4 }),
    };
    useDawStore.setState({ tracks, clips });

    const { result } = renderHook(() =>
      useArrangementInteractions(defaultView, "1/4"),
    );

    // Double-click at x=360 (time = (360-160)/100 = 2.0)
    act(() => {
      result.current.onDoubleClick(
        mockMouseEvent({ clientX: 360, clientY: 50 }),
      );
    });

    const clip = useDawStore.getState().clips["c1"];
    expect(clip).toBeDefined();
    if (clip !== undefined) {
      expect(clip.duration).toBe(1); // 2.0 - 1.0
    }
    expect(Object.keys(useDawStore.getState().clips)).toHaveLength(2);
    expect(sharedUndoManager.canUndo).toBe(true);
  });

  it("shift-click toggles clip selection", () => {
    const tracks = [makeTrack({ id: "t1", clipIds: ["c1", "c2"] })];
    const clips: Record<string, ClipModel> = {
      c1: makeClip({ id: "c1", trackId: "t1", startTime: 0, duration: 1 }),
      c2: makeClip({ id: "c2", trackId: "t1", startTime: 2, duration: 1 }),
    };
    useDawStore.setState({ tracks, clips, selectedClipIds: ["c1"] });

    const { result } = renderHook(() =>
      useArrangementInteractions(defaultView, "1/4"),
    );

    // Shift-click on c2 (x = 160 + 2*100 + 50 = 410, y = 50)
    act(() => {
      result.current.onPointerDown(
        mockPointerEvent({ clientX: 410, clientY: 50, shiftKey: true }),
      );
    });

    const selected = useDawStore.getState().selectedClipIds;
    expect(selected).toContain("c1");
    expect(selected).toContain("c2");
  });

  it("pushes undo command after move-clip drag", () => {
    const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
    const clips: Record<string, ClipModel> = {
      c1: makeClip({ id: "c1", trackId: "t1", startTime: 1, duration: 2 }),
    };
    useDawStore.setState({ tracks, clips });

    const { result } = renderHook(() =>
      useArrangementInteractions(defaultView, "1/4"),
    );

    // Click center of clip
    act(() => {
      result.current.onPointerDown(
        mockPointerEvent({ clientX: 360, clientY: 50 }),
      );
    });

    // Drag 100px right (= 1 second at 100 pps)
    act(() => {
      result.current.onPointerMove(
        mockPointerEvent({ clientX: 460, clientY: 50 }),
      );
    });

    // Release
    act(() => {
      result.current.onPointerUp(
        mockPointerEvent({ clientX: 460, clientY: 50 }),
      );
    });

    const clip = useDawStore.getState().clips["c1"];
    expect(clip?.startTime).toBeGreaterThan(1);
    expect(sharedUndoManager.canUndo).toBe(true);

    // Undo should restore original position
    sharedUndoManager.undo();
    expect(useDawStore.getState().clips["c1"]?.startTime).toBe(1);
  });

  it("split undo restores original clip", () => {
    const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
    const clips: Record<string, ClipModel> = {
      c1: makeClip({ id: "c1", trackId: "t1", startTime: 1, duration: 4 }),
    };
    useDawStore.setState({ tracks, clips });

    const { result } = renderHook(() =>
      useArrangementInteractions(defaultView, "1/4"),
    );

    act(() => {
      result.current.onDoubleClick(
        mockMouseEvent({ clientX: 360, clientY: 50 }),
      );
    });

    expect(Object.keys(useDawStore.getState().clips)).toHaveLength(2);

    sharedUndoManager.undo();

    const restored = useDawStore.getState().clips["c1"];
    expect(restored?.startTime).toBe(1);
    expect(restored?.duration).toBe(4);
    expect(Object.keys(useDawStore.getState().clips)).toHaveLength(1);
  });

  it("does not push undo when drag results in no change", () => {
    const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
    const clips: Record<string, ClipModel> = {
      c1: makeClip({ id: "c1", trackId: "t1", startTime: 1, duration: 2 }),
    };
    useDawStore.setState({ tracks, clips });

    const { result } = renderHook(() =>
      useArrangementInteractions(defaultView, "1/4"),
    );

    // Click and immediately release (no move)
    act(() => {
      result.current.onPointerDown(
        mockPointerEvent({ clientX: 360, clientY: 50 }),
      );
    });
    act(() => {
      result.current.onPointerUp(
        mockPointerEvent({ clientX: 360, clientY: 50 }),
      );
    });

    expect(sharedUndoManager.canUndo).toBe(false);
  });
});

import { describe, it, expect } from "vitest";
import { clipSchema, trackSchema } from "./track-schema";

describe("clipSchema", () => {
  const validClip = {
    id: "clip-1",
    trackId: "track-1",
    sourceId: "source-1",
    startTime: 2.5,
    sourceOffset: 0,
    duration: 4.0,
    gain: 1.0,
    fadeIn: 0.01,
    fadeOut: 0.05,
    name: "Kick",
  };

  it("accepts a valid clip", () => {
    const result = clipSchema.safeParse(validClip);
    expect(result.success).toBe(true);
  });

  it("rejects negative startTime", () => {
    const result = clipSchema.safeParse({ ...validClip, startTime: -1 });
    expect(result.success).toBe(false);
  });

  it("rejects negative sourceOffset", () => {
    const result = clipSchema.safeParse({ ...validClip, sourceOffset: -0.5 });
    expect(result.success).toBe(false);
  });

  it("rejects gain above 2", () => {
    const result = clipSchema.safeParse({ ...validClip, gain: 3 });
    expect(result.success).toBe(false);
  });

  it("rejects negative duration", () => {
    const result = clipSchema.safeParse({ ...validClip, duration: -1 });
    expect(result.success).toBe(false);
  });

  it("accepts zero fadeIn/fadeOut", () => {
    const result = clipSchema.safeParse({
      ...validClip,
      fadeIn: 0,
      fadeOut: 0,
    });
    expect(result.success).toBe(true);
  });
});

describe("trackSchema", () => {
  const validTrack = {
    id: "track-1",
    name: "Track 1",
    type: "audio" as const,
    color: "#ff2d6f",
    muted: false,
    solo: false,
    armed: false,
    volume: 1.0,
    pan: 0,
    clipIds: ["clip-1", "clip-2"],
  };

  it("accepts a valid audio track", () => {
    const result = trackSchema.safeParse(validTrack);
    expect(result.success).toBe(true);
  });

  it("accepts a valid instrument track", () => {
    const result = trackSchema.safeParse({ ...validTrack, type: "instrument" });
    expect(result.success).toBe(true);
  });

  it("rejects unknown track type", () => {
    const result = trackSchema.safeParse({ ...validTrack, type: "midi" });
    expect(result.success).toBe(false);
  });

  it("rejects volume above 2", () => {
    const result = trackSchema.safeParse({ ...validTrack, volume: 2.5 });
    expect(result.success).toBe(false);
  });

  it("rejects pan outside -1..1", () => {
    expect(trackSchema.safeParse({ ...validTrack, pan: -1.5 }).success).toBe(
      false,
    );
    expect(trackSchema.safeParse({ ...validTrack, pan: 1.5 }).success).toBe(
      false,
    );
  });

  it("accepts empty clipIds", () => {
    const result = trackSchema.safeParse({ ...validTrack, clipIds: [] });
    expect(result.success).toBe(true);
  });
});

